import { Container, classes } from '@adobe-commerce/elsie/lib';
import { useCustomerDetails } from '@/order/hooks';
import { CustomerDetailsContent } from '@/order/components';
import { CustomerDetailsProps, NormalizeAddressProps } from '@/order/types';
import { useText } from '@adobe-commerce/elsie/i18n';

export const CustomerDetails: Container<CustomerDetailsProps> = ({
  paymentIconsMap,
  orderData,
  title,
  className,
  slots,
}) => {
  const translations = useText({
    emailTitle: 'Order.CustomerDetails.email.title',
    shippingAddressTitle: 'Order.CustomerDetails.shippingAddress.title',
    shippingMethodsTitle: 'Order.CustomerDetails.shippingMethods.title',
    billingAddressTitle: 'Order.CustomerDetails.billingAddress.title',
    paymentMethodsTitle: 'Order.CustomerDetails.paymentMethods.title',
    returnInformationTitle: 'Order.CustomerDetails.returnInformation.title',
    headerText: 'Order.CustomerDetails.headerText',
    freeShipping: 'Order.CustomerDetails.freeShipping',
    createdReturnAt: 'Order.CustomerDetails.orderReturnLabels.createdReturnAt',
    orderNumberLabel:
      'Order.CustomerDetails.orderReturnLabels.orderNumberLabel',
    returnStatusLabel:
      'Order.CustomerDetails.orderReturnLabels.returnStatusLabel',
  });

  const { order, normalizeAddress, loading } = useCustomerDetails({
    orderData,
  });

  return (
    <div className={classes(['order-customer-details', className])}>
      <CustomerDetailsContent
        slots={slots}
        loading={loading}
        order={order}
        title={title}
        paymentIconsMap={paymentIconsMap}
        normalizeAddress={
          normalizeAddress as {
            billingAddress: [] | NormalizeAddressProps[][];
            shippingAddress: [] | NormalizeAddressProps[][];
          }
        }
        translations={translations}
      />
    </div>
  );
};
