import { useCallback, useEffect, useState } from 'preact/hooks';
import { useText } from '@adobe-commerce/elsie/i18n';
import { UseOrderActionsProps } from '@/order/types';
import { confirmGuestReturn, confirmCancelOrder } from '@/order/api';
import { removeQueryParams } from '@/order/lib/removeQueryParams';

export const useOrderActions = ({
  enableOrderCancellation,
}: UseOrderActionsProps) => {
  const translations = useText({
    cancelOrderHeading: 'Order.OrderStatusContent.actions.cancel',
    confirmGuestReturnHeading:
      'Order.OrderStatusContent.actions.confirmGuestReturn',
    orderCancelled: 'Order.OrderStatusContent.orderCanceled.message',
    guestRequestReturnMessage:
      'Order.OrderStatusContent.actions.confirmGuestReturnMessage',
  });
  const [isDismissed, setIsDismissed] = useState<boolean>(false);
  const [isExecuted, setIsExecuted] = useState<boolean>(false);
  const [orderActionStatus, setOrderActionStatus] = useState<{
    heading: string;
    text: string;
    status: 'success' | 'error' | 'warning' | undefined;
  }>({
    heading: '',
    text: '',
    status: undefined,
  });

  const onDismiss = useCallback(() => {
    setIsDismissed(true);
    removeQueryParams(['order_id', 'confirmation_key', 'action']);
  }, []);

  const triggerAlertOnDismiss = useCallback(
    (
      heading: string,
      text: string,
      status: 'success' | 'error' | 'warning' | undefined
    ) => {
      setOrderActionStatus({
        heading,
        text,
        status,
      });

      removeQueryParams(['action']);
    },
    []
  );

  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const orderId = params.get('order_id') ?? '';
    const confirmationKey = params.get('confirmation_key') ?? '';
    const actionType = params.get('action') ?? '';

    if (isExecuted || !orderId || !confirmationKey || !actionType) return;

    if (enableOrderCancellation && actionType === 'cancel') {
      setIsExecuted(true);
      confirmCancelOrder(orderId, confirmationKey)
        .then(() => {
          setOrderActionStatus({
            heading: translations.cancelOrderHeading,
            text: translations.orderCancelled,
            status: 'success',
          });
        })
        .catch((error) => {
          setOrderActionStatus({
            heading: translations.cancelOrderHeading,
            text: error.message,
            status: 'warning',
          });
        });
    }

    if (actionType === 'return') {
      setIsExecuted(true);
      confirmGuestReturn(orderId, confirmationKey)
        .then(() => {
          setOrderActionStatus({
            heading: translations.confirmGuestReturnHeading,
            text: translations.guestRequestReturnMessage,
            status: 'success',
          });
        })
        .catch((error) => {
          setOrderActionStatus({
            heading: translations.confirmGuestReturnHeading,
            text: error.message,
            status: 'warning',
          });
        });
    }
  }, [
    enableOrderCancellation,
    translations,
    triggerAlertOnDismiss,
    isExecuted,
  ]);

  return {
    orderActionStatus,
    isDismissed,
    onDismiss,
  };
};
