import { FunctionComponent } from 'preact';
import { classes, Slot } from '@adobe-commerce/elsie/lib';
import {
  Card,
  Header,
  Icon,
  IconNode,
  IconType,
  Price,
} from '@adobe-commerce/elsie/components';
import { Text } from '@adobe-commerce/elsie/i18n';
import {
  CustomerDetailsContentProps,
  NormalizeAddressProps,
} from '@/order/types';
import { DetailsSkeleton } from '@/order/components';
import { Card as CreditCard, Wallet } from '@adobe-commerce/elsie/icons';
import { useMemo } from 'preact/hooks';
import { formatReturnStatus } from '@/order/lib/returnOrdersHelper';
import { formatDateToLocale } from '@/order/lib/formatDateToLocale';
import '@/order/components/CustomerDetailsContent/CustomerDetailsContent.css';

const renderAddressData = (
  normalizeAddress: {
    billingAddress: NormalizeAddressProps[][];
    shippingAddress: NormalizeAddressProps[][];
  },
  type: 'shippingAddress' | 'billingAddress'
) => {
  const getFieldContent = (field: any) => {
    const value = Array.isArray(field.value)
      ? field.value.join(' ')
      : field?.value;
    return field.label ? `${field.label}: ${value}` : value;
  };

  return normalizeAddress[type]?.map((field: any, fieldIndex: number) => {
    return <p key={`${field.value}${fieldIndex}`}>{getFieldContent(field)}</p>;
  });
};

const extractPaymentMethodsData = (
  paymentMethods: { code: string; name: string }[]
) => {
  const hasPaymentMethod = paymentMethods && paymentMethods.length > 0;
  const selectedPaymentMethod = hasPaymentMethod ? paymentMethods[0]?.name : '';
  const selectedPaymentMethodCode = hasPaymentMethod
    ? paymentMethods[0]?.code
    : '';
  const hasToDisplayPaymentMethod =
    hasPaymentMethod && selectedPaymentMethod !== '';
  return {
    selectedPaymentMethod,
    selectedPaymentMethodCode,
    hasToDisplayPaymentMethod,
  };
};

export const CustomerDetailsContent: FunctionComponent<
  CustomerDetailsContentProps
> = ({
  loading,
  order,
  withHeader = true,
  title,
  paymentIconsMap = {},
  normalizeAddress,
  translations,
  slots,
}) => {
  const isReturnPage = !!order?.returnNumber;
  const isVirtual = !!order?.isVirtual;
  const orderReturn = order?.returns?.[0];

  const iconsList: Record<string, IconType | IconNode> = useMemo(
    () => ({
      checkmo: Wallet,
      card: CreditCard,
      ...paymentIconsMap,
    }),
    [paymentIconsMap]
  );

  if (!order || loading) return <DetailsSkeleton />;

  const emailAddress = order?.email ?? '';
  const shippingMethod = order?.shipping?.code;
  const shippingCost = order?.shipping?.amount;
  const shippingCurrency = order?.shipping?.currency;
  const paymentMethods = order?.payments;
  const {
    selectedPaymentMethod,
    selectedPaymentMethodCode,
    hasToDisplayPaymentMethod,
  } = extractPaymentMethodsData(paymentMethods);
  const paymentMethodIconSource = iconsList[selectedPaymentMethodCode];
  const shippingAddress =
    renderAddressData(normalizeAddress, 'shippingAddress') ?? [];
  const billingAddress =
    renderAddressData(normalizeAddress, 'billingAddress') ?? [];

  const contactDetails = (
    <div className="order-customer-details-content__container-email">
      <div className={'order-customer-details-content__container-title'}>
        {translations?.emailTitle}
      </div>
      <p>{emailAddress}</p>
    </div>
  );

  const returnDetails = isReturnPage ? (
    <div
      className="order-customer-details-content__container-return-information"
      data-testid="returnDetailsBlock"
    >
      <div className={'order-customer-details-content__container-title'}>
        {translations?.returnInformationTitle}
      </div>
      <div className="order-customer-details-content__container-description">
        <Slot
          data-testid="OrderReturnInformation"
          name="OrderReturnInformation"
          slot={slots?.OrderReturnInformation}
          context={orderReturn}
        >
          <>
            <p>
              {translations.createdReturnAt}
              <span>{formatDateToLocale(orderReturn?.createdReturnAt!)}</span>
            </p>
            <p>
              {translations.returnStatusLabel}
              <Text
                id={`Order.CustomerDetails.returnStatus.${formatReturnStatus(
                  orderReturn?.returnStatus!
                )}`}
              />
            </p>
            <p>
              {translations.orderNumberLabel}
              <span>{orderReturn?.orderNumber}</span>
            </p>
          </>
        </Slot>
      </div>
    </div>
  ) : null;

  const shippingAddressDetails =
    !isVirtual && shippingAddress.length ? (
      <div className="order-customer-details-content__container-shipping_address">
        <div className={'order-customer-details-content__container-title'}>
          {translations.shippingAddressTitle}
        </div>
        <div className="order-customer-details-content__container-description">
          {shippingAddress}
        </div>
      </div>
    ) : null;

  const billingAddressDetails = billingAddress.length ? (
    <div
      className={classes([
        'order-customer-details-content__container-billing_address',
        [
          'order-customer-details-content__container-billing_address--fullwidth',
          !shippingAddress.length || isVirtual,
        ],
      ])}
    >
      <div className={'order-customer-details-content__container-title'}>
        {translations.billingAddressTitle}
      </div>
      <div className="order-customer-details-content__container-description">
        {billingAddress}
      </div>
    </div>
  ) : null;

  const paymentMethodDetails = hasToDisplayPaymentMethod ? (
    <div
      className={classes([
        'order-customer-details-content__container-payment_methods',
        [
          'order-customer-details-content__container-payment_methods--fullwidth',
          !shippingMethod,
        ],
      ])}
    >
      <div className={'order-customer-details-content__container-title'}>
        {translations?.paymentMethodsTitle}
      </div>
      <p
        data-testid="payment_methods_description"
        className={classes([
          [
            'order-customer-details-content__container-payment_methods--icon',
            !!paymentMethodIconSource,
          ],
        ])}
      >
        <Slot
          data-testid="PaymentMethodIcon"
          name="PaymentMethodIcon"
          slot={slots?.PaymentMethodIcon}
          context={{ selectedPaymentMethodCode }}
        >
          {paymentMethodIconSource ? (
            <Icon source={paymentMethodIconSource} />
          ) : null}
        </Slot>
        {selectedPaymentMethod}
      </p>
    </div>
  ) : null;

  const shippingMethodDetails = shippingMethod ? (
    <div className="order-customer-details-content__container-shipping_methods">
      <div className={'order-customer-details-content__container-title'}>
        {translations?.shippingMethodsTitle}
      </div>
      {shippingCost ? (
        <p data-testid="shipping_methods_price">
          <Price amount={shippingCost} currency={shippingCurrency} />{' '}
          {shippingMethod}
        </p>
      ) : (
        <p data-testid="shipping_methods_placeholder">
          {translations?.freeShipping}
        </p>
      )}
    </div>
  ) : null;

  const pageSpecificDetails = isReturnPage ? (
    returnDetails
  ) : (
    <>
      {billingAddressDetails}
      {shippingMethodDetails}
      {paymentMethodDetails}
    </>
  );

  return (
    <Card
      data-testid="order-details"
      variant={'secondary'}
      className={classes(['order-customer-details-content'])}
    >
      {withHeader ? <Header title={title ?? translations?.headerText} /> : null}

      <div
        className={classes([
          'order-customer-details-content__container',
          [
            'order-customer-details-content__container--no-margin',
            shippingAddress.length || billingAddress.length,
          ],
        ])}
      >
        {contactDetails}
        {shippingAddressDetails}
        {pageSpecificDetails}
      </div>
    </Card>
  );
};
