import { getAttributesForm } from '@/order/api';
import { defaultAttributePreset } from '@/order/configs/defaultAttributePreset.config';
import { OrderDataModel } from '@/order/data/models';
import { convertToCamelCase } from '@/order/lib/convertCase';
import {
  KeysSortOrderProps,
  NormalizeAddressProps,
  UseCustomerDetails,
} from '@/order/types';
import { events } from '@adobe-commerce/event-bus';
import { useState, useEffect, useMemo, useCallback } from 'preact/hooks';

export const useCustomerDetails = ({ orderData }: UseCustomerDetails) => {
  const [loading, setLoading] = useState<boolean>(true);
  const [order, setOrder] = useState(orderData);
  const [keysSortOrder, setKeysSortOrder] = useState<KeysSortOrderProps[] | []>(
    []
  );

  useEffect(() => {
    const event = events.on(
      'order/data',
      (order: OrderDataModel) => {
        setOrder(order);
      },
      { eager: true }
    );

    return () => {
      event?.off();
    };
  }, []);

  useEffect(() => {
    getAttributesForm('shortRequest')
      .then((attributesFormResponse) => {
        if (attributesFormResponse) {
          const result: KeysSortOrderProps[] = attributesFormResponse.map(
            ({ name, orderNumber, label }) => ({
              name: convertToCamelCase(name as string),
              orderNumber,
              label: !defaultAttributePreset.includes(name as string)
                ? label
                : null,
            })
          );

          setKeysSortOrder(result);
        }
      })
      .finally(() => {
        setLoading(false);
      });
  }, []);

  const getNormalizeAddress = useCallback(
    (
      type: 'billingAddress' | 'shippingAddress'
    ): NormalizeAddressProps[] | [] => {
      if (!keysSortOrder.length || !order || !order[type]) return [];

      const address: Record<string, unknown> = order[type]
        ? Object.fromEntries(
            Object.entries(order[type] as Record<string, unknown>).map(
              ([key, value]) => [key.toLowerCase(), value]
            )
          )
        : {};

      // @ts-ignore
      return keysSortOrder
        .filter(({ name }) => address[name.toLowerCase()])
        .map((item) => {
          return {
            name: item.name,
            orderNumber: item.orderNumber,
            value: address[item.name.toLowerCase()],
            label: item.label,
          };
        });
    },
    [keysSortOrder, order]
  );

  const normalizeAddress = useMemo(
    () => ({
      billingAddress: getNormalizeAddress('billingAddress'),
      shippingAddress: getNormalizeAddress('shippingAddress'),
    }),
    [getNormalizeAddress]
  );

  return { order, normalizeAddress, loading };
};
