import { Button, Card, Icon, InLineAlert } from '@adobe-commerce/elsie/components';
import { Text } from '@adobe-commerce/elsie/i18n';
import { WarningFilled } from '@adobe-commerce/elsie/icons';
import { FunctionComponent } from 'preact';
import { OrderSearchFormProps } from '@/order/types';
import { Form } from '@/order/components';
import '@/order/components/OrderSearchForm/OrderSearchForm.css';

export const OrderSearchForm: FunctionComponent<OrderSearchFormProps> = ({
  onSubmit,
  loading,
  inLineAlert,
  fieldsConfig,
}) => {
  return (
    <Card variant={'secondary'} className={'order-order-search-form'}>
      <h2 className={'order-order-search-form__title'}>
        <Text id={'Order.OrderSearchForm.title'} />
      </h2>

      <p>
        <Text id={'Order.OrderSearchForm.description'} />
      </p>
      {inLineAlert.text ? (
        <InLineAlert
          data-testid="orderAlert"
          className={'order-order-search-form__alert'}
          type={inLineAlert.type}
          variant="secondary"
          heading={inLineAlert.text}
          icon={<Icon source={WarningFilled} />}
        />
      ) : null}

      <Form
        className={'order-order-search-form__wrapper'}
        name="orderSearchForm"
        loading={loading}
        fieldsConfig={fieldsConfig}
        onSubmit={onSubmit}
      >
        <div className="order-order-search-form__button-container">
          <Button
            className={'order-order-search-form__button'}
            size={'medium'}
            variant={'primary'}
            key={'logIn'}
            type={'submit'}
            disabled={loading}
          >
            <Text id={'Order.OrderSearchForm.button'} />
          </Button>
        </div>
      </Form>
    </Card>
  );
};
