import { CardLoader, OrderComments as OrderCommentsComponent } from '@/order/components';
import { OrderCommentsProps } from '@/order/types';
import { classes, Container } from '@adobe-commerce/elsie/lib';
import { useOrderComments } from '@/order/hooks';

export const OrderComments: Container<OrderCommentsProps> = ({
  orderData,
  className,
  ...props
}) => {
  const { comments, order } = useOrderComments({ orderData });

  if (!order) {
    return (
      <div className={classes(['order-order-comments-container', className])}>
        <CardLoader withCard={false} />
      </div>
    );
  }

  return (
    <div
      {...props}
      className={classes(['order-order-comments-container', className])}
    >
      <OrderCommentsComponent comments={comments} />
    </div>
  );
};
