import { OrderDataModel } from '@/order/data/models';
import { transformCustomerAddressInput } from '@/order/data/transforms/transform-customer-address-input';
import { SignUpContext, UseOrderHeaderProps } from '@/order/types';
import { events } from '@adobe-commerce/event-bus';
import { useEffect, useState } from 'preact/hooks';

export const useOrderHeader = ({
  orderData,
  handleEmailAvailability,
  handleSignUpClick,
}: UseOrderHeaderProps) => {
  const [order, setOrder] = useState(orderData);
  const [isAuthenticated, setIsAuthenticated] = useState<boolean | undefined>();
  const [isEmailAvailable, setIsEmailAvailable] = useState<boolean | undefined>(
    handleEmailAvailability ? undefined : true
  );

  const customerEmail = order?.email;

  const canCreateNewAccount =
    handleSignUpClick &&
    order !== undefined &&
    isAuthenticated === false &&
    isEmailAvailable === true;

  const onSignUpClickHandler = canCreateNewAccount
    ? () => {
      const shippingAddress = order.shippingAddress;
      const billingAddress = order.billingAddress;

      const inputsDefaultValueSet: SignUpContext['inputsDefaultValueSet'] = [
        { code: 'email', defaultValue: order.email },
        { code: 'firstname', defaultValue: billingAddress?.firstName ?? '' },
        { code: 'lastname', defaultValue: billingAddress?.lastName ?? '' },
      ];

      let addressesData: SignUpContext['addressesData'] = [];

      if (shippingAddress) {
        const customerShippingAddress = {
          ...transformCustomerAddressInput(shippingAddress),
          default_shipping: true,
        };
        const customerBillingAddress = {
          ...transformCustomerAddressInput(billingAddress),
          default_billing: true,
        };
        addressesData = [customerBillingAddress, customerShippingAddress];
      } else {
        const customerAddress = {
          ...transformCustomerAddressInput(billingAddress),
          default_billing: true,
          default_shipping: true,
        };
        addressesData = [customerAddress];
      }

      handleSignUpClick({ inputsDefaultValueSet, addressesData });
    }
    : undefined;

  useEffect(() => {
    const event = events.on(
      'authenticated',
      (authenticated) => {
        setIsAuthenticated(authenticated);
      },
      { eager: true }
    );

    return () => {
      event?.off();
    };
  }, []);

  useEffect(() => {
    const event = events.on(
      'order/data',
      (order: OrderDataModel) => {
        setOrder(order);
      },
      { eager: true }
    );

    return () => {
      event?.off();
    };
  }, []);

  useEffect(() => {
    if (!handleEmailAvailability) return;
    if (isAuthenticated === undefined) return;
    if (isAuthenticated || !customerEmail) return;

    handleEmailAvailability(customerEmail)
      .then((result) => setIsEmailAvailable(result))
      .catch(() => setIsEmailAvailable(true));
  }, [isAuthenticated, handleEmailAvailability, customerEmail]);

  return { order, onSignUpClickHandler };
};
