import { FunctionComponent } from 'preact';
import { useMemo } from 'preact/compat';
import { classes, Slot } from '@adobe-commerce/elsie/lib';
import { AvailableActionsProps, OrderActionsProps } from '@/order/types';
import { useText } from '@adobe-commerce/elsie/i18n';
import { Button } from '@adobe-commerce/elsie/components';
import { redirectTo } from '@/order/lib/redirectTo';
import '@/order/components/OrderActions/OrderActions.css';
import { OrderCancel, Reorder } from '@/order/components';

export const OrderActions: FunctionComponent<OrderActionsProps> = ({
  className,
  orderData,
  slots,
  routeCreateReturn,
  routeOnSuccess,
  onError,
}) => {
  const translationActions = useText({
    cancel: 'Order.OrderStatusContent.actions.cancel',
    createReturn: 'Order.OrderStatusContent.actions.createReturn',
    createAnotherReturn: 'Order.OrderStatusContent.actions.createAnotherReturn',
    reorder: 'Order.OrderStatusContent.actions.reorder',
  });

  const renderAvailableActions = useMemo(() => {
    const availableActionsList = orderData?.availableActions;
    const isEmpty = !!availableActionsList?.length;
    const isReturnPage = !!orderData?.returnNumber;

    const redirectToCreateReturn = () => {
      redirectTo(routeCreateReturn, {}, orderData);
    };

    return (
      <>
        {slots?.OrderActions ? (
          <Slot
            data-testid="OrderActionsSlot"
            name="OrderCanceledActions"
            slot={slots?.OrderActions}
            context={orderData}
          />
        ) : (
          <div
            data-testid="availableActionsList"
            className={classes([
              'order-order-actions__wrapper',
              ['order-order-actions__wrapper--empty', !isEmpty],
            ])}
          >
            {(availableActionsList as AvailableActionsProps[])?.map(
              (action: string) => {
                switch (action) {
                  case AvailableActionsProps.CANCEL:
                    // Cancel action should not be available on return details page
                    return (
                      <>
                        {!isReturnPage ? (
                          <OrderCancel
                            orderRef={orderData?.token! || orderData?.id!}
                          />
                        ) : null}
                      </>
                    );
                  case AvailableActionsProps.RETURN:
                    return (
                      <Button
                        variant="secondary"
                        onClick={redirectToCreateReturn}
                      >
                        {isReturnPage
                          ? translationActions.createAnotherReturn
                          : translationActions.createReturn}
                      </Button>
                    );
                  case AvailableActionsProps.REORDER:
                    // Reorder action should not be available on return details page
                    return (
                      <>
                        {!isReturnPage ? (
                          <Reorder
                            orderData={orderData}
                            onError={onError}
                            routeOnSuccess={routeOnSuccess}
                          >
                            {translationActions.reorder}
                          </Reorder>
                        ) : null}
                      </>
                    );
                }
              }
            )}
          </div>
        )}
      </>
    );
  }, [
    onError,
    orderData,
    routeOnSuccess,
    routeCreateReturn,
    slots,
    translationActions,
  ]);

  return (
    <div className={classes(['order-order-actions', className])}>
      {renderAvailableActions}
    </div>
  );
};
