import { Button, InLineAlert, Picker } from '@adobe-commerce/elsie/components';
import '@/order/containers/OrderCancelForm/OrderCancelForm.css';
import { Text, useText } from '@adobe-commerce/elsie/i18n';
import { Form } from '@/order/components';
import { useState } from 'preact/hooks';
import { OrderCancelFormProps } from '@/order/types';
import { OrderDataModel } from '@/order/data/models';
import { events } from '@adobe-commerce/event-bus';
import { Container } from '@adobe-commerce/elsie/lib';
import { cancelOrder, requestGuestOrderCancel } from '@/order/api';

export const OrderCancelForm: Container<OrderCancelFormProps> = ({
  orderRef,
  pickerProps,
  submitButtonProps,
  cancelReasons,
}) => {
  const translations = useText({
    ErrorHeading: 'Order.OrderCancelForm.errorHeading',
    ErrorDescription: 'Order.OrderCancelForm.errorDescription',
    orderCancellationLabel: 'Order.OrderCancelForm.label',
  });

  const [selectedReason, setSelectedReason] = useState<number>(0);
  const [isErrorVisible, setIsErrorVisible] = useState<boolean>(false);
  const [isCustomerAuthenticated, setIsCustomerAuthenticated] = useState(false);
  events.on(
    'authenticated',
    (authenticated) => {
      if (authenticated) {
        setIsCustomerAuthenticated(true);
      }
    },
    { eager: true } // fetch it on runtime using last state
  );

  const handleReasonSelect = (event: Event) => {
    event.preventDefault();

    const value = Number((event.target as HTMLSelectElement).value);
    setSelectedReason(value);
  };

  const onSubmit = async (
    event: SubmitEvent
  ): Promise<void | null | undefined> => {
    event.preventDefault();
    const cancelOrderMutation =
      orderRef.length > 20 ? requestGuestOrderCancel : cancelOrder;
    return cancelOrderMutation(
      orderRef,
      cancelReasons[selectedReason].text!,
      (data: OrderDataModel) => {
        if (!isCustomerAuthenticated) {
          data.status = 'guest order cancellation requested';
        }
        events.emit('order/data', data);
      },
      () => {
        setIsErrorVisible(true);
      }
    );
  };

  return (
    <Form
      onSubmit={onSubmit}
      data-testid="order-order-cancel-reasons-form__text"
    >
      {isErrorVisible && (
        <InLineAlert
          heading={translations.ErrorHeading}
          description={translations.ErrorDescription}
        />
      )}
      <div className="order-order-cancel-reasons-form__text">
        <Text id={'Order.OrderCancelForm.description'} />
      </div>
      <Picker
        name="cancellationReasons"
        floatingLabel={translations.orderCancellationLabel}
        defaultOption={cancelReasons[0]}
        variant="primary"
        options={cancelReasons}
        value={String(selectedReason)}
        handleSelect={handleReasonSelect}
        required={true}
        data-testid="order-cancellation-reasons-selector"
        {...pickerProps}
      />
      <div className="order-order-cancel-reasons-form__button-container">
        <Button
          variant="primary"
          data-testid="order-cancel-submit-button"
          {...submitButtonProps}
        >
          <Text id={'Order.OrderCancelForm.button'} />
        </Button>
      </div>
    </Form>
  );
};
