import { getCustomerOrdersReturn } from '@/order/api';
import { OrdersReturnPropsModel } from '@/order/data/models';
import { UseReturnsListProps } from '@/order/types';
import { useCallback, useEffect, useState } from 'preact/hooks';

const DEFAULT_PAGE_INFO = { totalPages: 1, currentPage: 1, pageSize: 1 };

export const useReturnsList = ({ returnPageSize }: UseReturnsListProps) => {
  const [loading, setLoading] = useState(true);
  const [orderReturns, setOrderReturns] = useState<
    OrdersReturnPropsModel[] | []
  >([]);

  const [pageInfo, setPageInfo] = useState<{
    totalPages: number;
    currentPage: number;
    pageSize: number;
  }>(DEFAULT_PAGE_INFO);

  const [selectedPage, setSelectedPage] = useState<number>(1);

  useEffect(() => {
    getCustomerOrdersReturn(returnPageSize, selectedPage)
      .then((response) => {
        setOrderReturns(response?.ordersReturn ?? []);
        setPageInfo(response?.pageInfo ?? DEFAULT_PAGE_INFO);
      })
      .finally(() => {
        setLoading(false);
      });
  }, [returnPageSize, selectedPage]);

  useEffect(() => {
    const currentScrollY = window?.scrollY ?? 0;

    if (currentScrollY > 0) {
      window?.scrollTo({
        top: 100,
        behavior: 'smooth',
      });
    }
  }, [selectedPage]);

  const handleSetSelectPage = useCallback((value: number) => {
    setSelectedPage(value);
  }, []);

  return {
    pageInfo,
    selectedPage,
    loading,
    orderReturns,
    handleSetSelectPage,
  };
};
