import '@/order/components/OrderLoaders/OrderLoaders.css';
import {
  Card,
  CartItemSkeleton,
  Skeleton,
  SkeletonRow,
} from '@adobe-commerce/elsie/components';
import { classes } from '@adobe-commerce/elsie/lib';

export const CardLoader = ({
  testId,
  withCard = true,
}: {
  testId?: string;
  withCard?: boolean;
}) => {
  const defaultSkeleton = (
    <Skeleton data-testid={testId ?? 'skeletonLoader'}>
      <SkeletonRow
        variant="heading"
        size="xlarge"
        fullWidth={false}
        lines={1}
      />
      <SkeletonRow variant="heading" size="xlarge" fullWidth={true} lines={1} />
      <SkeletonRow variant="heading" size="xlarge" fullWidth={true} lines={1} />
    </Skeleton>
  );

  if (withCard) {
    return defaultSkeleton;
  }

  return (
    <Card
      variant="secondary"
      className={classes([
        'order-order-loaders',
        'order-order-loaders--card-loader',
      ])}
    >
      {defaultSkeleton}
    </Card>
  );
};

export const DetailsSkeleton = (props: any) => {
  return (
    <Card variant={'secondary'} {...props}>
      <Skeleton data-testid="order-details-skeleton">
        <SkeletonRow variant={'heading'} size="medium" fullWidth={true} />
        <SkeletonRow size="medium" />
        <SkeletonRow variant={'empty'} size="medium" />
        <SkeletonRow size="xlarge" />
        <SkeletonRow size="xlarge" />
        <SkeletonRow size="xlarge" />
        <SkeletonRow size="xlarge" />
      </Skeleton>
    </Card>
  );
};

export const OrderProductListSkeleton = () => {
  return (
    <Skeleton
      data-testid="order-product-list-skeleton"
      style={{ gridTemplateColumns: '1fr' }}
    >
      <SkeletonRow variant="heading" fullWidth={true} size="medium" />
      <CartItemSkeleton />
      <CartItemSkeleton />
      <CartItemSkeleton />
      <CartItemSkeleton />
      <CartItemSkeleton />
    </Skeleton>
  );
};

export const OrderSummarySkeleton = () => {
  return (
    <Skeleton
      data-testid="order-cost-summary-content-skeleton"
      className={'order-cost-summary-content'}
    >
      <SkeletonRow variant="heading" size="small" />
      <SkeletonRow variant="empty" size="small" />
      <SkeletonRow variant="empty" size="small" />
      <SkeletonRow variant="empty" size="small" />
      <SkeletonRow variant="heading" size="small" fullWidth={true} lines={3} />
    </Skeleton>
  );
};

export const OrderHeaderSkeleton = () => {
  return (
    <Skeleton data-testid="order-header-skeleton" className="order-header">
      <SkeletonRow variant="empty" size="xlarge" fullWidth={true} />
      <SkeletonRow variant="empty" size="medium" />
      <SkeletonRow variant="empty" size="medium" />
      <SkeletonRow variant="empty" size="medium" />
      <SkeletonRow variant="empty" size="medium" />
      <SkeletonRow variant="empty" size="medium" />
      <SkeletonRow size="small" fullWidth={true} />
      <SkeletonRow variant="heading" size="xsmall" fullWidth={true} />
    </Skeleton>
  );
};
