import {
  OrderHeader as OrderHeaderComponent,
  OrderHeaderSkeleton,
} from '@/order/components';
import { useOrderHeader } from '@/order/hooks/containers/useOrderHeader';
import { OrderHeaderProps } from '@/order/types';
import { FunctionComponent } from 'preact';

export const OrderHeader: FunctionComponent<OrderHeaderProps> = (props) => {
  const { order, onSignUpClickHandler } = useOrderHeader(props);

  return (
    <div>
      {order ? (
        <OrderHeaderComponent
          customerName={order.billingAddress?.firstName}
          onSignUpClick={onSignUpClickHandler}
          orderNumber={order.number}
        />
      ) : (
        <OrderHeaderSkeleton />
      )}
    </div>
  );
};
