import { OrderDataModel } from '@/order/data/models';
import { UseOrderCommentsProps } from '@/order/types';
import { events } from '@adobe-commerce/event-bus';
import { useEffect, useState } from 'preact/hooks';

export const useOrderComments = ({ orderData }: UseOrderCommentsProps) => {
  const [order, setOrder] = useState<OrderDataModel | null | undefined>(
    orderData ?? null
  );
  const [comments, setComments] = useState(orderData?.comments ?? []);

  useEffect(() => {
    const event = events.on(
      'order/data',
      (orderPayload: OrderDataModel) => {
        setOrder(orderPayload);
        setComments(orderPayload?.comments ?? []);
      },
      { eager: true }
    );

    return () => {
      event?.off();
    };
  }, []);

  return { comments, order };
};
