import { FunctionComponent } from 'preact';
import {
  CartItem,
  Image,
  Price,
  Icon,
  Incrementer,
} from '@adobe-commerce/elsie/components';
import { useCallback } from 'preact/hooks';
import { WarningWithCircle } from '@adobe-commerce/elsie/icons';
import { CartSummaryItemProps } from '@/order/types';
import { Slot } from '@adobe-commerce/elsie/lib';
import { OrderSummarySkeleton } from '../OrderLoaders';
import { OrderItemModel } from '@/order/data/models';

export const CartSummaryItem: FunctionComponent<CartSummaryItemProps> = ({
  slots,
  placeholderImage = '',
  loading,
  product,
  itemType,
  taxConfig,
  translations,
  disabledIncrementer,
  onQuantity,
  showConfigurableOptions,
  routeProductDetails,
}) => {
  const { taxExcluded, taxIncluded } = taxConfig;

  const renderDefaultPrice = useCallback(
    (amount: number, currency: string, configs?: any) => {
      return (
        <Price
          amount={amount}
          currency={currency}
          weight="normal"
          {...configs}
        />
      );
    },
    []
  );

  const renderImages = useCallback(
    (product: OrderItemModel) => {
      const label = product?.productName ?? '';

      const defaultImageProps = {
        title: label,
        src: product?.product?.thumbnail?.url ?? placeholderImage,
        alt: label,
        width: 90,
        height: 120,
        loading: 'lazy',
      } as const;

      return (
        <Slot
          slotTag="span"
          contentTag="span"
          data-testid={`cartSummaryItemImage-${product.id}`}
          name="CartSummaryItemImage"
          slot={slots?.CartSummaryItemImage}
          context={{
            data: product,
            defaultImageProps,
          }}
        >
          <Image {...defaultImageProps} />
        </Slot>
      );
    },
    [placeholderImage, slots?.CartSummaryItemImage]
  );

  if (!product) return <OrderSummarySkeleton />;

  let configPrice = {};
  const isCancelled = itemType === 'cancelled';
  const inStock = product?.product?.stockStatus?.includes('IN_STOCK');
  const giftCard = product?.giftCard;
  const renderQuantity =
    product.totalQuantity > 1 ? { quantity: product.totalQuantity } : {};
  const isDiscounted = product.discounted;
  const { includeAndExcludeTax, includeTax, excludeTax } =
    product.taxCalculations;
  const totalQuantity = product?.totalQuantity;
  const configurations = {
    ...(product?.configurableOptions || {}),
    ...(product?.bundleOptions || {}),
    ...(giftCard?.senderName
      ? { [translations.sender]: giftCard?.senderName }
      : {}),
    ...(giftCard?.senderEmail
      ? { [translations.sender]: giftCard?.senderEmail }
      : {}),
    ...(giftCard?.senderName
      ? { [translations.sender]: giftCard?.senderName }
      : {}),
    ...(giftCard?.recipientEmail
      ? { [translations.recipient]: giftCard?.recipientEmail }
      : {}),
    ...(giftCard?.message ? { [translations.message]: giftCard?.message } : {}),
    ...(product?.downloadableLinks
      ? {
          [`${product?.downloadableLinks?.count} ${translations.downloadableCount}`]:
            product?.downloadableLinks?.result,
        }
      : {}),
  };

  // Admin panel configuration - Sales -> Tax -> Order, Invoices, Credit Memos Display Settings
  // GraphQL field - orders_invoices_credit_memos_display_price field converted to taxIncluded & taxExcluded booleans
  if (taxIncluded && taxExcluded) {
    // Including and Excluding Tax option (value "3" in GraphQL)

    const singleItemPrice = renderDefaultPrice(
      includeAndExcludeTax.originalPrice.value,
      includeAndExcludeTax.originalPrice.currency
    );

    const totalOriginalPrice = renderDefaultPrice(
      includeAndExcludeTax.baseOriginalPrice.value * totalQuantity,
      includeAndExcludeTax.baseOriginalPrice.currency,
      {
        variant: product.discounted ? 'strikethrough' : 'default',
        weight: 'bold',
      }
    );

    const totalDiscountedPrice = renderDefaultPrice(
      includeAndExcludeTax.baseDiscountedPrice.value * totalQuantity,
      includeAndExcludeTax.baseDiscountedPrice.currency,
      { sale: true, weight: 'bold' }
    );

    const totalExcludingTax = renderDefaultPrice(
      includeAndExcludeTax.baseExcludingTax.value * totalQuantity,
      includeAndExcludeTax.baseExcludingTax.currency,
      { weight: 'bold' }
    );

    configPrice = {
      taxExcluded: true,
      taxIncluded: undefined,
      price: singleItemPrice,
      total: (
        <>
          {totalOriginalPrice}
          {product.discounted ? totalDiscountedPrice : null}
        </>
      ),
      totalExcludingTax,
    };
  } else if (!taxIncluded && taxExcluded) {
    // Excluding Tax option (value "1" in GraphQL)

    const singleItemPrice = renderDefaultPrice(
      excludeTax.originalPrice.value,
      excludeTax.originalPrice.currency
    );

    const totalOriginalPrice = renderDefaultPrice(
      excludeTax.baseOriginalPrice.value * totalQuantity,
      excludeTax.baseOriginalPrice.currency,
      {
        variant: isDiscounted ? 'strikethrough' : 'default',
        weight: 'bold',
      }
    );

    const totalDiscountedPrice = renderDefaultPrice(
      excludeTax.baseDiscountedPrice.value * totalQuantity,
      excludeTax.baseDiscountedPrice.currency,
      {
        sale: true,
        weight: 'bold',
      }
    );

    const totalExcludingTax = renderDefaultPrice(
      excludeTax.baseExcludingTax.value * totalQuantity,
      excludeTax.baseExcludingTax.currency,
      { weight: 'bold' }
    );

    configPrice = {
      taxExcluded: undefined,
      taxIncluded: undefined,
      price: singleItemPrice,
      total: (
        <>
          {totalOriginalPrice}
          {isDiscounted ? totalDiscountedPrice : null}
        </>
      ),
      totalExcludingTax,
    };
  } else if (taxIncluded && !taxExcluded) {
    // Including Tax option (value "2" in GraphQL)

    const singleItemPrice = renderDefaultPrice(
      includeTax.singleItemPrice.value,
      includeTax.singleItemPrice.currency
    );

    const totalOriginalPrice = renderDefaultPrice(
      includeTax.baseOriginalPrice.value * totalQuantity,
      includeTax.baseOriginalPrice.currency,
      {
        variant: isDiscounted ? 'strikethrough' : 'default',
        weight: 'bold',
      }
    );

    const totalDiscountedPrice = renderDefaultPrice(
      includeTax.baseDiscountedPrice.value * totalQuantity,
      includeTax.baseDiscountedPrice.currency,
      { sale: true, weight: 'bold' }
    );

    configPrice = {
      taxExcluded: undefined,
      taxIncluded: true,
      price: singleItemPrice,
      total: (
        <>
          {totalOriginalPrice}
          {isDiscounted ? totalDiscountedPrice : null}
        </>
      ),
    };
  }

  return (
    <CartItem
      loading={loading}
      alert={
        isCancelled && !inStock ? (
          <span>
            <Icon source={WarningWithCircle} />
            {translations.outOfStock}
          </span>
        ) : (
          <></>
        )
      }
      configurations={
        showConfigurableOptions?.(configurations) ?? configurations
      }
      title={
        routeProductDetails ? (
          <a
            data-testid="product-name"
            className='cart-summary-item__title'
            href={routeProductDetails(product)}
          >
            {product?.productName}
          </a>
        ) : (
          <div
            data-testid="product-name"
            className='cart-summary-item__title'
          >
            {product?.productName}
          </div>
        )
      }
      sku={<div>{product?.product?.sku}</div>}
      {...renderQuantity}
      image={
        routeProductDetails ? (
          <a href={routeProductDetails(product)}>{renderImages(product)}</a>
        ) : (
          renderImages(product)
        )
      }
      {...configPrice}
      footer={
        <>
          {onQuantity && !disabledIncrementer ? (
            <Incrementer
              value={1}
              min={1}
              max={product?.totalQuantity}
              onValue={(value) => onQuantity?.(Number(value))}
              name="quantity"
              data-testid="returnIncrementer"
              readonly
            />
          ) : undefined}

          <Slot
            data-testid="Footer"
            name="Footer"
            slot={slots?.Footer}
            context={{ item: product }}
          />
        </>
      }
    />
  );
};
