import { Button, Modal, PickerOption } from '@adobe-commerce/elsie/components';
import { OrderCancelProps } from '@/order/types';
import { useGetStoreConfig } from '@/order/hooks/api/useGetStoreConfig';
import { OrderCancellationReason } from '@/order/data/models';
import { OrderCancelForm } from '@/order/containers';
import { useState } from 'preact/hooks';
import { Text } from '@adobe-commerce/elsie/i18n';
import { events } from '@adobe-commerce/event-bus';
import '@/order/components/OrderCancel/OrderCancel.css';
import { FunctionComponent } from 'preact';

export const OrderCancel: FunctionComponent<OrderCancelProps> = ({
  orderRef,
}) => {
  const [isCancelReasonsModalVisible, setIsCancelReasonsModalVisible] =
    useState(false);

  const handleOpen = () => {
    setIsCancelReasonsModalVisible(true);
  };
  const handleClose = () => {
    setIsCancelReasonsModalVisible(false);
  };

  const storeConfig = useGetStoreConfig();
  const orderCancellationReasons = storeConfig?.orderCancellationReasons ?? [];

  const transformCancelReasons = (
    reasons: OrderCancellationReason[]
  ): PickerOption[] => {
    return reasons.map((reason, index) => {
      return {
        text: reason?.description,
        value: index.toString(),
      };
    });
  };

  events.on('order/data', (orderData) => {
    const status = String(orderData.status).toLocaleLowerCase();
    if (
      status === 'guest order cancellation requested' ||
      status === 'canceled'
    ) {
      handleClose();
    }
  });

  return (
    <>
      <Button
        variant="secondary"
        onClick={handleOpen}
        data-testid="cancel-button"
      >
        <Text id={'Order.OrderStatusContent.actions.cancel'} />
      </Button>
      {isCancelReasonsModalVisible && (
        <Modal
          centered={true}
          size="medium"
          onClose={handleClose}
          className={'order-order-cancel__modal'}
          title={
            <h2 className={'order-order-cancel__title'}>
              <Text id={'Order.OrderCancelForm.title'} />
            </h2>
          }
          data-testid="order-cancellation-reasons-modal"
        >
          <OrderCancelForm
            orderRef={orderRef}
            cancelReasons={transformCancelReasons(orderCancellationReasons)}
          />
        </Modal>
      )}
    </>
  );
};
