import '@/order/components/OrderHeader/OrderHeader.css';
import { Button, Header, Icon } from '@adobe-commerce/elsie/components';
import { Text, useText } from '@adobe-commerce/elsie/i18n';
import { OrderSuccess } from '@adobe-commerce/elsie/icons';
import { FunctionComponent } from 'preact';

export interface OrderHeaderProps {
  customerName?: string;
  onSignUpClick?: () => void;
  orderNumber: string;
}

export const OrderHeader: FunctionComponent<OrderHeaderProps> = ({
  customerName,
  orderNumber,
  onSignUpClick,
}) => {
  const translations = useText({
    title: (
      <Text id="Order.OrderHeader.title" fields={{ name: customerName }} />
    ),
    defaultTitle: 'Order.OrderHeader.defaultTitle',
    order: (
      <Text id="Order.OrderHeader.order" fields={{ order: orderNumber }} />
    ),
    createAccountMessage: 'Order.OrderHeader.CreateAccount.message',
    createAccountButton: 'Order.OrderHeader.CreateAccount.button',
  });

  return (
    <div data-testid="order-header" className="order-header order-header__card">
      <Icon source={OrderSuccess} size="64" className="order-header__icon" />

      <Header
        className="order-header__title"
        title={translations.title}
        size="large"
        divider={false}
      >
        {customerName ? translations.title : translations.defaultTitle}
      </Header>

      <p className="order-header__order">{translations.order}</p>

      {onSignUpClick && (
        <div className="order-header-create-account">
          <p className="order-header-create-account__message">
            {translations.createAccountMessage}
          </p>

          <Button
            data-testid="create-account-button"
            className="order-header-create-account__button"
            size="medium"
            variant="secondary"
            type="submit"
            onClick={onSignUpClick}
          >
            {translations.createAccountButton}
          </Button>
        </div>
      )}
    </div>
  );
};
