import { ReturnsListContent } from '@/order/components';
import { useGetStoreConfig, useIsMobile, useReturnsList } from '@/order/hooks';
import { ReturnsListProps } from '@/order/types';
import { classes, Container } from '@adobe-commerce/elsie/lib';
import { useText } from '@adobe-commerce/elsie/i18n';

export const ReturnsList: Container<ReturnsListProps> = ({
  slots,
  withReturnsListButton,
  className,
  minifiedView,
  withHeader,
  withThumbnails,
  returnPageSize,
  returnsInMinifiedView,
  routeReturnDetails,
  routeOrderDetails,
  routeTracking,
  routeReturnsList,
  routeProductDetails,
}) => {
  const storeConfig = useGetStoreConfig();
  const { pageInfo, selectedPage, handleSetSelectPage, loading, orderReturns } =
    useReturnsList({ returnPageSize });
  const isMobile = useIsMobile();

  const minifiedViewKey = minifiedView ? 'minifiedView' : 'fullSizeView';

  const translations = useText({
    viewAllOrdersButton: `Order.Returns.${minifiedViewKey}.returnsList.viewAllOrdersButton`,
    ariaLabelLink: `Order.Returns.${minifiedViewKey}.returnsList.ariaLabelLink`,
    emptyOrdersListMessage: `Order.Returns.${minifiedViewKey}.returnsList.emptyOrdersListMessage`,
    minifiedViewTitle: `Order.Returns.${minifiedViewKey}.returnsList.minifiedViewTitle`,
    orderNumber: `Order.Returns.${minifiedViewKey}.returnsList.orderNumber`,
    returnNumber: `Order.Returns.${minifiedViewKey}.returnsList.returnNumber`,
    carrier: `Order.Returns.${minifiedViewKey}.returnsList.carrier`,
  });

  return (
    <div className={classes(['order-returns-list', className])}>
      <ReturnsListContent
        placeholderImage={storeConfig?.baseMediaUrl ?? ''}
        minifiedViewKey={minifiedViewKey}
        withOrderNumber={true}
        withReturnNumber={true}
        slots={slots}
        selectedPage={selectedPage}
        handleSetSelectPage={handleSetSelectPage}
        pageInfo={pageInfo}
        withReturnsListButton={withReturnsListButton}
        isMobile={isMobile}
        orderReturns={orderReturns}
        translations={translations}
        withHeader={withHeader}
        returnsInMinifiedView={returnsInMinifiedView}
        withThumbnails={withThumbnails}
        minifiedView={minifiedView}
        routeReturnDetails={routeReturnDetails}
        routeOrderDetails={routeOrderDetails}
        routeTracking={routeTracking}
        routeReturnsList={routeReturnsList}
        routeProductDetails={routeProductDetails}
        loading={loading}
      />
    </div>
  );
};
