const DEFAULT_DATE_OPTIONS: Intl.DateTimeFormatOptions = {
  day: '2-digit',
  month: '2-digit',
  year: 'numeric',
};

const DATE_TIME_OPTIONS: Intl.DateTimeFormatOptions = {
  year: 'numeric',
  month: 'long',
  day: 'numeric',
  hour: '2-digit',
  minute: '2-digit',
  second: '2-digit',
  hour12: true,
};

const dateTimeFormatterCache = new Map<string, Intl.DateTimeFormat>();
const DATE_TIME_CACHE_MAX_SIZE = 16;

function getDateTimeFormatter(locale: string): Intl.DateTimeFormat {
  let formatter = dateTimeFormatterCache.get(locale);
  if (!formatter) {
    if (dateTimeFormatterCache.size >= DATE_TIME_CACHE_MAX_SIZE) {
      const firstKey = dateTimeFormatterCache.keys().next().value;
      if (firstKey !== undefined) dateTimeFormatterCache.delete(firstKey);
    }
    formatter = new Intl.DateTimeFormat(locale, DATE_TIME_OPTIONS);
    dateTimeFormatterCache.set(locale, formatter);
  }
  return formatter;
}

/** Use as third argument to format as date + time (e.g. "July 28, 2025, 2:26:04 PM"). */
export const FORMAT_DATETIME = 'datetime' as const;

export type FormatDateToLocaleOptions =
  | Intl.DateTimeFormatOptions
  | typeof FORMAT_DATETIME;

/**
 * Formats a date or date-time string according to locale and options.
 * Returns "Invalid Date" if the input is invalid.
 *
 * @param date - The date string (e.g. ISO 8601 or YYYY-MM-DD).
 * @param locale - The locale for formatting. Defaults to 'en-US'.
 * @param options - Format options: an object (date-only by default, merged with defaults), or FORMAT_DATETIME for long date+time (e.g. "July 28, 2025, 2:26:04 PM").
 * @returns The formatted string, or "Invalid Date" if invalid.
 *
 * @example
 * // Date only (MM/DD/YYYY)
 * formatDateToLocale('2023-08-29');
 * // => "08/29/2023"
 *
 * @example
 * // Date and time (long format, cached per locale)
 * formatDateToLocale('2024-10-10T12:00:00.000Z', 'en-US', FORMAT_DATETIME);
 * // => "October 10, 2024, 12:00:00 PM"
 *
 * @example
 * // Custom options
 * formatDateToLocale('2023-08-29', 'de-DE', { month: 'long', year: 'numeric' });
 * // => "29. August 2023"
 */
export const formatDateToLocale = (
  date: string,
  locale: string = 'en-US',
  options: FormatDateToLocaleOptions = {}
): string => {
  const dateObj = new Date(date);
  if (isNaN(dateObj.getTime())) {
    return 'Invalid Date';
  }

  if (options === FORMAT_DATETIME) {
    return getDateTimeFormatter(locale).format(dateObj);
  }

  const formatOptions: Intl.DateTimeFormatOptions = {
    ...DEFAULT_DATE_OPTIONS,
    ...options,
  };
  return new Intl.DateTimeFormat(locale, formatOptions).format(dateObj);
};
