// @ts-nocheck
import { FieldEnumList } from '@/order/types';
import { getFormValues } from './getFormValues';
const returnStatus = {
  PENDING: 'pending',
  AUTHORIZED: 'authorized',
  PARTIALLY_AUTHORIZED: 'partiallyAuthorized',
  RECEIVED: 'received',
  PARTIALLY_RECEIVED: 'partiallyReceived',
  APPROVED: 'approved',
  PARTIALLY_APPROVED: 'partiallyApproved',
  REJECTED: 'rejected',
  PARTIALLY_REJECTED: 'partiallyRejected',
  DENIED: 'denied',
  PROCESSED_AND_CLOSED: 'processedAndClosed',
  CLOSED: 'closed',
} as const;

type ReturnStatusKey = keyof typeof returnStatus;
type ReturnStatusValue = (typeof returnStatus)[ReturnStatusKey];
type KeyValueObject = { [key: string]: any };
type returnAttributesType = Array<{ attributeCode: string; value: string }>;
type normalizeAttributesTypes = {
  selectedCustomAttributes: returnAttributesType;
  enteredCustomAttributes: returnAttributesType;
};

const formatTemplate = (el, index) => {
  return {
    id: `${el.id}_${el.fieldType}_${index + 1}`,
    name: `${el.name}_${el.fieldType}_${index + 1}`,
    code: `${el.code}_${el.fieldType}_${index + 1}`,
    customUpperCode: `${el.customUpperCode}_${el.fieldType}_${index + 1}`,
  };
};

export const cleanObjectKeys = (obj: KeyValueObject): KeyValueObject => {
  const cleanedObject: KeyValueObject = {};

  if (!obj || typeof obj !== 'object' || Object.keys(obj).length === 0) {
    return cleanedObject;
  }

  Object.keys(obj).forEach((key) => {
    const match = /_(\d+)$/.exec(key);

    if (match) {
      const newKey = key?.replace(/_\d+$/, '');
      cleanedObject[newKey] = obj[key];
    } else {
      cleanedObject[key] = obj[key];
    }
  });

  return cleanedObject;
};

export const modifyFieldsConfig = (fieldsConfig, index: number) =>
  fieldsConfig.map((el) => ({
    ...el,
    ...formatTemplate(el, index),
  }));

export const replicateEntries = (objects: any[], n: number): any[] =>
  objects?.flatMap((el) =>
    Array.from({ length: n }, (_, index) => ({
      ...el,
      ...formatTemplate(el, index),
    }))
  );

export const normalizeAttributes = (
  obj: Record<string, string>
): normalizeAttributesTypes => {
  const selectedCustomAttributes: returnAttributesType = [];
  const enteredCustomAttributes: returnAttributesType = [];

  Object.entries(obj).forEach(([key, value]) => {
    const lastUnderscoreIndex = key.lastIndexOf('_');
    const baseKey = key.slice(0, lastUnderscoreIndex);
    const type = key.slice(lastUnderscoreIndex + 1);

    type === FieldEnumList.MULTISELECT || type === FieldEnumList.SELECT
      ? selectedCustomAttributes.push({
          attributeCode: baseKey,
          value,
        })
      : enteredCustomAttributes.push({ attributeCode: baseKey, value });
  });

  return { selectedCustomAttributes, enteredCustomAttributes };
};

export const formatReturnStatus = (str: string): ReturnStatusValue | '' => {
  if (typeof str !== 'string') return '';

  return returnStatus[str as ReturnStatusKey] ?? '';
};

export const processFormElement = (formsRef) => {
  const items: any[] = [];

  if (formsRef?.current.length) {
    for (const { current } of formsRef.current) {
      if (!current) continue;

      const orderItemUid = current.name.replace(/_\d+$/, '');
      const quantity = current?.dataset?.quantity ?? 1;
      const formsData = getFormValues(current as HTMLFormElement);
      const valuesList = cleanObjectKeys(formsData);

      items.push({
        orderItemUid,
        quantityToReturn: +quantity,
        ...normalizeAttributes(valuesList),
      });
    }
  }

  return items;
};

export const sortItemsByCondition = (order) => {
  if (!order?.items?.length) return [];

  return [...(order?.items ?? [])].sort((a, b) => {
    const aCondition = a.quantityShipped - a.quantityReturnRequested === 0;
    const bCondition = b.quantityShipped - b.quantityReturnRequested === 0;

    if (a.eligibleForReturn && !b.eligibleForReturn) return -1;
    if (!a.eligibleForReturn && b.eligibleForReturn) return 1;

    if (aCondition && !bCondition) return 1;
    if (!aCondition && bCondition) return -1;
    return 0;
  });
};
