import { useCallback, useEffect, useMemo, useState } from 'preact/hooks';
import {
  FieldEnumList,
  inLineAlertProps,
  useOrderSearchProps,
} from '@/order/types';
import { getFormValues } from '@/order/lib/getFormValues';
import { getCustomer, getGuestOrder } from '@/order/api';
import { useText } from '@adobe-commerce/elsie/i18n';
import { events } from '@adobe-commerce/event-bus';
import { OrderDataModel } from '@/order/data/models';
import { redirectTo } from '@/order/lib/redirectTo';
import { getQueryParam } from '@/order/lib/getQueryParam';

export const useOrderSearch = ({
  onError,
  isAuth,
  renderSignIn,
  routeCustomerOrder,
  routeGuestOrder,
}: useOrderSearchProps) => {
  const [inLineAlert, setInLineAlert] = useState<inLineAlertProps>({
    text: '',
    type: 'success',
  });
  const [loading, setLoading] = useState(false);

  const translations = useText({
    invalidSearch: 'Order.Errors.invalidSearch',
    email: 'Order.OrderSearchForm.email',
    lastname: 'Order.OrderSearchForm.lastname',
    number: 'Order.OrderSearchForm.orderNumber',
  });

  const orderSearchRedirect = useCallback(
    async (order: OrderDataModel) => {
      const orderRef = getQueryParam('orderRef');
      const isToken = orderRef && orderRef.length > 20;
      const dataIsEmpty =
        (!order && !orderRef) || (!order?.number && !order?.token && !orderRef);

      if (dataIsEmpty) return null;

      if (isAuth) {
        const customer = await getCustomer();

        if (customer?.email === order.email) {
          redirectTo(routeCustomerOrder, {
            orderRef: order?.number,
          });
        } else if (!isToken) {
          redirectTo(routeGuestOrder, { orderRef: order.token! });
        }
      } else if (!isToken) {
        redirectTo(routeGuestOrder, { orderRef: order?.token! });
      }
    },
    [isAuth, routeCustomerOrder, routeGuestOrder]
  );

  useEffect(() => {
    const event = events.on(
      'order/data',
      (order: OrderDataModel) => {
        orderSearchRedirect(order);
      },
      { eager: true }
    );

    return () => {
      event?.off();
    };
  }, [orderSearchRedirect]);

  useEffect(() => {
    const orderRef = getQueryParam('orderRef');
    const isToken = orderRef && orderRef.length > 20 ? orderRef : null;

    if (!orderRef) return;

    if (isToken) {
      redirectTo(routeGuestOrder, { orderRef });
    } else if (isAuth) {
      redirectTo(routeCustomerOrder, { orderRef });
    } else {
      renderSignIn?.({ render: true, formValues: { number: orderRef } });
    }
  }, [isAuth, routeCustomerOrder, routeGuestOrder, renderSignIn]);

  const normalizeFieldsConfig = useMemo(() => {
    return [
      {
        entityType: 'CUSTOMER_ADDRESS',
        is_unique: false,
        label: translations.email,
        options: [],
        defaultValue: '',
        fieldType: FieldEnumList.TEXT,
        className: '',
        required: true,
        orderNumber: 1,
        name: 'email',
        id: 'email',
        code: 'email',
        isUnique: false,
      },
      {
        entityType: 'CUSTOMER_ADDRESS',
        is_unique: false,
        label: translations.lastname,
        options: [],
        defaultValue: '',
        fieldType: FieldEnumList.TEXT,
        className: '',
        required: true,
        orderNumber: 2,
        name: 'lastname',
        id: 'lastname',
        code: 'lastname',
        isUnique: false,
      },
      {
        entityType: 'CUSTOMER_ADDRESS',
        is_unique: false,
        label: translations.number,
        options: [],
        defaultValue: '',
        fieldType: FieldEnumList.TEXT,
        className: '',
        required: true,
        orderNumber: 3,
        name: 'number',
        id: 'number',
        code: 'number',
        isUnique: false,
      },
    ];
  }, [translations]);

  const onSubmit = useCallback(
    async (event: Event, valid: boolean) => {
      if (!valid) return null;

      setLoading(true);

      const formValues = getFormValues(event.target as HTMLFormElement);

      await getGuestOrder(formValues)
        .then((guestOrder) => {
          if (!guestOrder) {
            setInLineAlert({
              text: translations.invalidSearch,
              type: 'warning',
            });
          }

          events.emit('order/data', guestOrder as OrderDataModel);
        })
        .catch(async (error) => {
          let showErrorMessage: boolean | undefined = true;

          onError?.({
            error: error.message,
          });

          const customer = isAuth ? await getCustomer() : { email: '' };

          const isOrderBelongsToCustomer =
            customer?.email === formValues?.email;

          if (isOrderBelongsToCustomer) {
            redirectTo(routeCustomerOrder, { orderRef: formValues.number });

            return;
          }

          showErrorMessage = renderSignIn?.({
            render:
              customer === null ||
              error?.message?.includes('Please login to view the order.'),
            formValues,
          });

          if (showErrorMessage) {
            setInLineAlert({
              text: error.message,
              type: 'warning',
            });
          }
        })
        .finally(() => {
          setLoading(false);
        });
    },
    [
      isAuth,
      onError,
      renderSignIn,
      routeCustomerOrder,
      translations.invalidSearch,
    ]
  );

  return { onSubmit, inLineAlert, loading, normalizeFieldsConfig };
};
