import { FunctionComponent } from 'preact';
import { Card, Header } from '@adobe-commerce/elsie/components';
import { OrderStatusContentProps, StatusEnumProps } from '@/order/types';
import { useText } from '@adobe-commerce/elsie/i18n';
import { OrderActions } from '@/order/components';
import { formatReturnStatus } from '@/order/lib/returnOrdersHelper';
import { classes } from '@adobe-commerce/elsie/lib';
import { formatDateToLocale } from '@/order/lib/formatDateToLocale';
import '@/order/components/OrderStatusContent/OrderStatusContent.css';
import { capitalizeFirst } from '@/order/lib/capitalizeFirst';

const statusTransform: Record<string, string> = {
  pending: 'orderPending',
  shiping: 'orderShipped',
  complete: 'orderComplete',
  processing: 'orderProcessing',
  'on hold': 'orderOnHold',
  canceled: 'orderCanceled',
  'suspected fraud': 'orderSuspectedFraud',
  'payment Review': 'orderPaymentReview',
  'order received': 'orderReceived',
  'guest order cancellation requested': 'guestOrderCancellationRequested',
  'pending payment': 'orderPendingPayment',
  rejected: 'orderRejected',
  authorized: 'orderAuthorized',
  'paypal canceled reversal': 'orderPaypalCanceledReversal',
  'pending paypal': 'orderPendingPaypal',
  'paypal reversed': 'orderPaypalReversed',
  closed: 'orderClosed',
};

export const OrderStatusContent: FunctionComponent<OrderStatusContentProps> = ({
  slots,
  title,
  status,
  orderData,
  routeCreateReturn,
  onError,
  routeOnSuccess,
}) => {
  const isReturnPage = !!orderData?.returnNumber;
  const orderStatus = String(status).toLocaleLowerCase();
  const orderReturn = orderData?.returns?.[0];
  const orderReturnStatus = orderReturn?.returnStatus ?? '';
  const createdReturnAt = orderReturn?.createdReturnAt ?? '';

  const translationsPlaceholder = useText({
    message: 'Order.OrderStatusContent.orderPlaceholder.message',
    messageWithoutDate:
      'Order.OrderStatusContent.orderPlaceholder.messageWithoutDate',
  });

  const translationsHeader = useText(
    `Order.OrderStatusContent.${
      statusTransform[orderStatus as StatusEnumProps]
    }.title`
  );

  const translationsMessage = useText(
    `Order.OrderStatusContent.${
      statusTransform[orderStatus as StatusEnumProps]
    }.message`
  );

  const translationsMessageWithoutDate = useText(
    `Order.OrderStatusContent.${
      statusTransform[orderStatus as StatusEnumProps]
    }.messageWithoutDate`
  );

  const translationsReturn = useText({
    title: `Order.OrderStatusContent.returnStatus.${formatReturnStatus(
      orderReturnStatus
    )}`,
    returnMessage: 'Order.OrderStatusContent.returnMessage',
  });

  const translationsOrder = useText({
    adminAssistedLabel: 'Order.OrderStatusContent.adminAssistedLabel',
  });

  if (!status) return <div />;

  const translationsHeaderTitle = translationsHeader?.title
    ? translationsHeader
    : { title: capitalizeFirst(orderStatus) };
  const translationsText = translationsMessage?.message
    ? translationsMessage
    : translationsPlaceholder;
  const translationsTextWithoutDate =
    translationsMessageWithoutDate?.messageWithoutDate
      ? translationsMessageWithoutDate
      : translationsPlaceholder;

  const orderMessage = orderData?.orderStatusChangeDate
    ? translationsText?.message.replace(
        '{DATE}',
        formatDateToLocale(orderData?.orderStatusChangeDate)
      )
    : translationsTextWithoutDate.messageWithoutDate;

  const isAdminAssisted = orderData?.adminAssistedOrder;

  const returnMessage =
    translationsReturn?.returnMessage
      ?.replace(
        '{ORDER_CREATE_DATE}',
        formatDateToLocale(orderData?.orderDate!)
      )
      ?.replace('{RETURN_CREATE_DATE}', formatDateToLocale(createdReturnAt)) ??
    '';

  const headerTitle = isReturnPage
    ? title ?? (translationsReturn.title || capitalizeFirst(orderReturnStatus))
    : title ?? translationsHeaderTitle.title;

  return (
    <Card className="order-order-status-content" variant="secondary">
      <Header title={headerTitle} />
      <div className="order-order-status-content__wrapper">
        <div
          className={classes([
            'order-order-status-content__wrapper-description',
            [
              'order-order-status-content__wrapper-description--actions-slot',
              !!slots?.OrderActions,
            ],
          ])}
        >
          {isAdminAssisted && (
            <p className="order-order-status-content__admin-assisted">
              {translationsOrder?.adminAssistedLabel}
            </p>
          )}
          <p>{isReturnPage ? returnMessage : orderMessage}</p>
        </div>
        <OrderActions
          orderData={orderData}
          slots={slots}
          routeCreateReturn={routeCreateReturn}
          routeOnSuccess={routeOnSuccess}
          onError={onError}
        />
      </div>
    </Card>
  );
};
