import { classes, Container } from '@adobe-commerce/elsie/lib';
import { OrderSearchForm } from '@/order/components';
import { useOrderSearch } from '@/order/hooks';
import { FieldsProps, OrderSearchProps } from '@/order/types';

export const OrderSearch: Container<OrderSearchProps> = ({
  className,
  isAuth,
  renderSignIn,
  routeCustomerOrder,
  routeGuestOrder,
  onError,
}) => {
  const { onSubmit, loading, inLineAlert, normalizeFieldsConfig } =
    useOrderSearch({
      onError,
      isAuth,
      renderSignIn,
      routeCustomerOrder,
      routeGuestOrder,
    });

  return (
    <div className={classes(['order-order-search', className])}>
      <OrderSearchForm
        onSubmit={onSubmit}
        loading={loading}
        inLineAlert={inLineAlert}
        fieldsConfig={normalizeFieldsConfig as FieldsProps[]}
      />
    </div>
  );
};
