import { getStoreConfig } from '@/order/api';
import { useEffect, useState } from 'preact/hooks';
import { StoreConfigModel } from '../../data/models';

export const useGetStoreConfig = () => {
  const [config, setConfig] = useState<StoreConfigModel | null>(null);

  useEffect(() => {
    const storeConfigPromiseKey = 'orderStoreConfigPromise';

    const storeConfigString = sessionStorage.getItem('orderStoreConfig');

    if (storeConfigString) {
      // If the data is already cached in sessionStorage, use it
      const cachedStoreConfig: StoreConfigModel = JSON.parse(storeConfigString);
      setConfig(cachedStoreConfig);
    } else {
      // This part required to get rid of TS errors
      const windowWithPromise = window as typeof window & {
        [key: string]: Promise<StoreConfigModel | null> | undefined;
      };

      // Check if there's already a global promise for fetching store config
      if (!windowWithPromise[storeConfigPromiseKey]) {
        // If not, create one and store it in the global window object
        windowWithPromise[storeConfigPromiseKey] = getStoreConfig().then(
          (response) => {
            if (response) {
              sessionStorage.setItem(
                'orderStoreConfig',
                JSON.stringify(response)
              );
            }
            return response;
          }
        );
      }

      // Use the promise from the global window object
      windowWithPromise[storeConfigPromiseKey]?.then((response) => {
        if (response) {
          setConfig(response);
        }
      });
    }
  }, []);

  return config;
};
