import { FunctionComponent } from 'preact';
import { Card, Header } from '@adobe-commerce/elsie/components';
import { classes } from '@adobe-commerce/elsie/lib';
import { useText } from '@adobe-commerce/elsie/i18n';
import {
  formatDateToLocale,
  FORMAT_DATETIME,
} from '@/order/lib/formatDateToLocale';
import { OrderCommentsComponentProps } from '@/order/types';
import '@/order/components/OrderComments/OrderComments.css';

export const OrderComments: FunctionComponent<OrderCommentsComponentProps> = ({
  className,
  comments = [],
  ...props
}) => {
  const dictionary = useText({
    emptyState: 'Order.OrderComments.emptyState',
    title: 'Order.OrderComments.title',
  });

  const listContent =
    !comments || comments.length === 0 ? (
      <ul
        className={classes([
          'order-order-comments',
          'order-order-comments--empty',
        ])}
        data-testid="order-comments-list"
      >
        <li
          className="order-order-comments__empty-state"
          data-testid="order-comments-empty-state"
        >
          {dictionary.emptyState}
        </li>
      </ul>
    ) : (
      <ul
        className="order-order-comments"
        data-testid="order-comments-list"
      >
        {comments.map((comment, i) => (
          <li
            key={i}
            className="order-order-comments__item"
            data-testid={`order-comment-${i}`}
          >
            <div className="order-order-comments__header">
              <time
                className="order-order-comments__date"
                dateTime={comment.timestamp}
                data-testid={`order-comment-date-${i}`}
              >
                {formatDateToLocale(comment.timestamp, 'en-US', FORMAT_DATETIME)}
              </time>
            </div>
            <p
              className="order-order-comments__text"
              data-testid={`order-comment-text-${i}`}
            >
              {comment.message}
            </p>
          </li>
        ))}
      </ul>
    );

  return (
    <Card
      {...props}
      variant="secondary"
      className={classes(['order-order-comments-card', className])}
      data-testid="order-comments-card"
    >
      <Header title={dictionary.title} />
      <div className="order-order-comments-card__container">
        {listContent}
      </div>
    </Card>
  );
};
