import { CardLoader, OrderStatusContent } from '@/order/components';
import { OrderStatusProps } from '@/order/types';
import { classes, Container } from '@adobe-commerce/elsie/lib';
import {
  useOrderActions,
  useGetStoreConfig,
  useOrderStatus,
} from '@/order/hooks';
import { InLineAlert } from '@adobe-commerce/elsie/components';

export const OrderStatus: Container<OrderStatusProps> = ({
  slots,
  orderData,
  className,
  statusTitle,
  status,
  routeCreateReturn,
  onError,
  routeOnSuccess,
}) => {
  const { orderStatus, order } = useOrderStatus({ orderData });

  const storeConfig = useGetStoreConfig();

  const { orderActionStatus, isDismissed, onDismiss } = useOrderActions({
    enableOrderCancellation: storeConfig?.orderCancellationEnabled,
  });

  return (
    <div className={classes(['order-order-status', className])}>
      {!isDismissed && orderActionStatus?.status !== undefined ? (
        <InLineAlert
          style={{ marginBottom: '1rem' }}
          heading={orderActionStatus.heading}
          onDismiss={onDismiss}
          description={orderActionStatus.text}
          type={orderActionStatus.status}
        />
      ) : null}
      {order ? (
        <OrderStatusContent
          title={statusTitle}
          status={status || orderStatus}
          slots={slots}
          orderData={order}
          routeCreateReturn={routeCreateReturn}
          onError={onError}
          routeOnSuccess={routeOnSuccess}
        />
      ) : (
        <CardLoader withCard={false} />
      )}
    </div>
  );
};
