import { FunctionComponent } from 'preact';
import { Button } from '@adobe-commerce/elsie/components';
import { redirectTo } from '@/order/lib/redirectTo';
import { reorderItems } from '@/order/api';
import { useCallback, useState } from 'preact/hooks';
import { ReorderProps } from '@/order/types';

export const Reorder: FunctionComponent<ReorderProps> = ({
  onError,
  routeOnSuccess,
  orderData,
  children,
}) => {
  const [loading, setLoading] = useState(false);

  const mutationReorderItems = useCallback(() => {
    setLoading(true);
    const orderNumber = orderData?.number!;

    reorderItems(orderNumber)
      .then(({ success, userInputErrors }) => {
        if (success) {
          redirectTo(routeOnSuccess, {});
        }

        if (userInputErrors.length) {
          onError?.(userInputErrors);
        }
      })
      .catch((error) => {
        onError?.(error.message as string);
      })
      .finally(() => {
        setLoading(false);
      });
  }, [orderData, routeOnSuccess, onError]);

  return (
    <Button
      type="button"
      disabled={loading}
      variant="secondary"
      className={'order-reorder'}
      onClick={mutationReorderItems}
    >
      {children}
    </Button>
  );
};
